"use client";

import { useMemo } from "react";
import { LogOutIcon, SparklesIcon } from "lucide-react";
import { usePathname, useRouter } from "next/navigation";
import { MobileNav } from "@/components/layout/mobile-nav";
import { SessionList } from "@/components/layout/session-list";
import { SidebarNav } from "@/components/layout/sidebar-nav";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { useAuth } from "@/providers/auth-provider";

const sectionMeta = {
  chat: {
    title: "Agent workspace",
    description: "Conversational analysis across metrics, experiments, and artifacts.",
  },
  metrics: {
    title: "Metrics explorer",
    description: "Metric definitions and compiled SQL.",
  },
  experiments: {
    title: "Experiments explorer",
    description: "Experiment configs and analysis plans.",
  },
  artifacts: {
    title: "Artifact library",
    description: "Search and read team-authored Markdown outputs.",
  },
} as const;

export function AppShell({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  const pathname = usePathname();
  const router = useRouter();
  const { auth, logout } = useAuth();

  const currentSection = useMemo(() => {
    if (pathname.startsWith("/app/metrics")) return "metrics";
    if (pathname.startsWith("/app/experiments")) return "experiments";
    if (pathname.startsWith("/app/artifacts")) return "artifacts";
    return "chat";
  }, [pathname]);

  const meta = sectionMeta[currentSection];
  const isChatSection = currentSection === "chat";

  return (
    <div className="mx-auto flex h-screen w-full max-w-[1660px] gap-4 overflow-hidden px-3 py-3 sm:px-4 sm:py-4">
      <aside
        className={`surface-panel hidden h-full shrink-0 md:flex md:flex-col ${
          isChatSection ? "w-[272px]" : "w-[320px]"
        }`}
      >
        <div className="flex items-center gap-3 border-b border-border/70 px-4 py-4">
          <div className="flex size-10 items-center justify-center rounded-[1rem] bg-primary text-primary-foreground shadow-sm">
            <SparklesIcon className="size-[18px]" />
          </div>
          <div className="min-w-0">
          <p className="truncate text-[15px] font-semibold leading-5">Crew Beta</p>
            <p className="truncate text-[11px] text-muted-foreground">
              Collaborative analysis
            </p>
          </div>
        </div>
        <div className="flex flex-1 flex-col gap-5 overflow-y-auto px-3.5 py-4">
          <div className="space-y-3">
            <div className="px-1">
              <p className="text-[11px] font-semibold uppercase tracking-[0.14em] text-muted-foreground">
                Workspace
              </p>
            </div>
            <SidebarNav />
          </div>
          <Separator />
          <SessionList />
        </div>
        <div className="border-t border-border/70 px-3.5 py-3">
          <div className="flex items-center gap-2">
            <div className="min-w-0 flex-1 rounded-full border border-border/80 bg-white/70 px-3 py-2 text-sm font-medium">
              <span className="truncate block">@{auth?.user.username}</span>
            </div>
            <Button
              variant="outline"
              size="icon"
              className="size-10"
              onClick={() => {
                logout();
                router.replace("/login");
              }}
            >
              <LogOutIcon className="size-4" />
              <span className="sr-only">Log out</span>
            </Button>
          </div>
        </div>
      </aside>

      <div className="flex min-h-0 min-w-0 flex-1 flex-col gap-4 overflow-hidden">
        {!isChatSection ? (
          <header className="surface-panel px-4 py-4 sm:px-5">
            <div className="flex items-start justify-between gap-4">
              <div className="flex min-w-0 items-start gap-3">
                <MobileNav />
                <div className="min-w-0">
                  <h1 className="text-xl font-semibold sm:text-2xl">{meta.title}</h1>
                  <p className="mt-1 max-w-3xl text-sm text-muted-foreground">
                    {meta.description}
                  </p>
                </div>
              </div>

              <div className="flex shrink-0 items-center gap-2">
                <div className="hidden rounded-full border border-border/80 bg-white/80 px-3 py-2 text-right shadow-sm sm:block">
                  <p className="text-sm font-medium">@{auth?.user.username}</p>
                </div>
                <Button
                  variant="outline"
                  size="icon"
                  onClick={() => {
                    logout();
                    router.replace("/login");
                  }}
                >
                  <LogOutIcon className="size-4" />
                  <span className="sr-only">Log out</span>
                </Button>
              </div>
            </div>
          </header>
        ) : null}

        <main className="min-h-0 flex-1 overflow-hidden">{children}</main>
      </div>
    </div>
  );
}
